/** Unique identifier for a built-in theme. */
export type ThemeId = "t3-dark" | "t3-light" | "t3-midnight";

/** Color tokens that every theme must define. */
export interface ThemeColorTokens {
  /** Main application background */
  readonly background: string;
  /** Primary text color */
  readonly foreground: string;
  /** Accent / primary highlight color */
  readonly accent: string;
  /** Text color on accent surfaces */
  readonly accentForeground: string;
  /** Sidebar background */
  readonly sidebar: string;
  /** Sidebar text color */
  readonly sidebarForeground: string;
  /** Editor / content area background */
  readonly editor: string;
  /** Editor text color */
  readonly editorForeground: string;
  /** Terminal panel background */
  readonly terminal: string;
  /** Terminal text color */
  readonly terminalForeground: string;
  /** Status bar background */
  readonly statusBar: string;
  /** Status bar text color */
  readonly statusBarForeground: string;
}

/** Full definition of a theme preset. */
export interface ThemeDefinition {
  /** Unique theme identifier */
  readonly id: ThemeId;
  /** Human-readable display name */
  readonly name: string;
  /** Whether this theme uses a light or dark base (controls the root `.dark` class) */
  readonly base: "light" | "dark";
  /** Color palette for the theme */
  readonly colors: ThemeColorTokens;
}

/* ---------------------------------------------------------------------------
 * Built-in theme definitions
 * ------------------------------------------------------------------------- */

const t3Light: ThemeDefinition = {
  id: "t3-light",
  name: "T3 Light",
  base: "light",
  colors: {
    background: "#ffffff",
    foreground: "#262626",
    accent: "#6d28d9",
    accentForeground: "#ffffff",
    sidebar: "#f5f5f5",
    sidebarForeground: "#262626",
    editor: "#ffffff",
    editorForeground: "#262626",
    terminal: "#1e1e1e",
    terminalForeground: "#d4d4d4",
    statusBar: "#6d28d9",
    statusBarForeground: "#ffffff",
  },
};

const t3Dark: ThemeDefinition = {
  id: "t3-dark",
  name: "T3 Dark",
  base: "dark",
  colors: {
    background: "#0a0a0a",
    foreground: "#f5f5f5",
    accent: "#8b5cf6",
    accentForeground: "#ffffff",
    sidebar: "#141414",
    sidebarForeground: "#f5f5f5",
    editor: "#0a0a0a",
    editorForeground: "#f5f5f5",
    terminal: "#0a0a0a",
    terminalForeground: "#d4d4d4",
    statusBar: "#7c3aed",
    statusBarForeground: "#ffffff",
  },
};

const t3Midnight: ThemeDefinition = {
  id: "t3-midnight",
  name: "T3 Midnight",
  base: "dark",
  colors: {
    background: "#0b1120",
    foreground: "#e2e8f0",
    accent: "#38bdf8",
    accentForeground: "#0b1120",
    sidebar: "#0f172a",
    sidebarForeground: "#cbd5e1",
    editor: "#0b1120",
    editorForeground: "#e2e8f0",
    terminal: "#020617",
    terminalForeground: "#94a3b8",
    statusBar: "#1e3a5f",
    statusBarForeground: "#e2e8f0",
  },
};

/** All built-in themes ordered for display. */
export const BUILT_IN_THEMES: readonly ThemeDefinition[] = [t3Light, t3Dark, t3Midnight];

/** Map of theme IDs to definitions for O(1) lookup. */
const THEMES_BY_ID: Record<ThemeId, ThemeDefinition> = {
  "t3-light": t3Light,
  "t3-dark": t3Dark,
  "t3-midnight": t3Midnight,
};

/** Retrieve a built-in theme definition by its ID. */
export function getThemeById(id: ThemeId): ThemeDefinition {
  return THEMES_BY_ID[id];
}

/** Type guard that checks if a string is a valid ThemeId. */
export function isThemeId(value: string): value is ThemeId {
  return value in THEMES_BY_ID;
}

/**
 * The CSS custom property names applied by the theme provider, keyed by
 * `ThemeColorTokens` property name. For example, `sidebar` maps to
 * `--theme-sidebar`.
 */
export const THEME_CSS_PROPERTIES: Record<keyof ThemeColorTokens, string> = {
  background: "--theme-background",
  foreground: "--theme-foreground",
  accent: "--theme-accent",
  accentForeground: "--theme-accent-foreground",
  sidebar: "--theme-sidebar",
  sidebarForeground: "--theme-sidebar-foreground",
  editor: "--theme-editor",
  editorForeground: "--theme-editor-foreground",
  terminal: "--theme-terminal",
  terminalForeground: "--theme-terminal-foreground",
  statusBar: "--theme-status-bar",
  statusBarForeground: "--theme-status-bar-foreground",
};

