import { createContext, useContext, type ReactNode } from "react";
import type { ThemeDefinition } from "@t3tools/shared/theme";
import { useTheme, type ThemePreference } from "../hooks/useTheme";

interface ThemeContextValue {
  /** Current user preference (may be "system"). */
  theme: ThemePreference;
  /** Persist a new theme preference. */
  setTheme: (next: ThemePreference) => void;
  /** Resolved to "light" or "dark". */
  resolvedTheme: "light" | "dark";
  /** The full resolved theme definition. */
  themeDefinition: ThemeDefinition;
}

const ThemeContext = createContext<ThemeContextValue | null>(null);

/**
 * Wraps the component tree and provides theme state via context.
 *
 * CSS custom properties (`--theme-*`) are applied to `<html>` as a side
 * effect of the underlying `useTheme` hook, so every descendant — including
 * plain CSS — automatically picks up the active palette.
 */
export function ThemeProvider({ children }: { children: ReactNode }) {
  const value = useTheme();
  return <ThemeContext.Provider value={value}>{children}</ThemeContext.Provider>;
}

/**
 * Read the current theme from the nearest `<ThemeProvider>`.
 *
 * @throws if called outside a `<ThemeProvider>`.
 */
export function useThemeContext(): ThemeContextValue {
  const ctx = useContext(ThemeContext);
  if (!ctx) {
    throw new Error("useThemeContext must be used within a <ThemeProvider>");
  }
  return ctx;
}

