import { BUILT_IN_THEMES, type ThemeDefinition } from "@t3tools/shared/theme";
import { useTheme, type ThemePreference } from "../hooks/useTheme";
import { cn } from "../lib/utils";

/* ---------------------------------------------------------------------------
 * Static option list — "system" first, then one entry per built-in theme.
 * ------------------------------------------------------------------------- */

const THEME_OPTIONS: ReadonlyArray<{
  value: ThemePreference;
  label: string;
  description: string;
  definition: ThemeDefinition | null;
}> = [
  {
    value: "system",
    label: "System",
    description: "Automatically match your OS appearance.",
    definition: null,
  },
  ...BUILT_IN_THEMES.map((t) => ({
    value: t.id as ThemePreference,
    label: t.name,
    description: `${t.base === "dark" ? "Dark" : "Light"} theme with ${t.id === "t3-midnight" ? "a deep navy" : t.base === "dark" ? "a neutral dark" : "a clean light"} palette.`,
    definition: t,
  })),
];

/* ---------------------------------------------------------------------------
 * Swatch row — renders a compact color preview for one theme.
 * ------------------------------------------------------------------------- */

function ThemeSwatch({ theme }: { theme: ThemeDefinition }) {
  const { colors } = theme;
  const swatchColors = [
    { color: colors.background, label: "background" },
    { color: colors.sidebar, label: "sidebar" },
    { color: colors.accent, label: "accent" },
    { color: colors.editor, label: "editor" },
    { color: colors.terminal, label: "terminal" },
    { color: colors.statusBar, label: "status bar" },
  ];

  return (
    <div className="flex gap-1" aria-hidden="true">
      {swatchColors.map((swatch) => (
        <span
          key={swatch.label}
          className="size-4 rounded-sm border border-border/50"
          style={{ backgroundColor: swatch.color }}
          title={swatch.label}
        />
      ))}
    </div>
  );
}

/* ---------------------------------------------------------------------------
 * ThemeSelector — full radio-group UI with swatches.
 * ------------------------------------------------------------------------- */

export function ThemeSelector() {
  const { theme, setTheme, resolvedTheme, themeDefinition } = useTheme();

  return (
    <div className="space-y-3">
      <div className="space-y-2" role="radiogroup" aria-label="Theme preference">
        {THEME_OPTIONS.map((option) => {
          const selected = theme === option.value;
          return (
            <button
              key={option.value}
              type="button"
              role="radio"
              aria-checked={selected}
              className={cn(
                "flex w-full items-start justify-between gap-3 rounded-lg border px-3 py-2.5 text-left transition-colors",
                selected
                  ? "border-primary/60 bg-primary/8 text-foreground"
                  : "border-border bg-background text-muted-foreground hover:bg-accent",
              )}
              onClick={() => setTheme(option.value)}
            >
              <span className="flex flex-col gap-1.5">
                <span className="text-sm font-medium">{option.label}</span>
                <span className="text-xs">{option.description}</span>
                {option.definition ? <ThemeSwatch theme={option.definition} /> : null}
              </span>
              {selected ? (
                <span className="shrink-0 rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
                  Selected
                </span>
              ) : null}
            </button>
          );
        })}
      </div>

      <p className="text-xs text-muted-foreground">
        Active theme:{" "}
        <span className="font-medium text-foreground">{themeDefinition.name}</span>
        {" "}({resolvedTheme})
      </p>
    </div>
  );
}

